INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000200', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 133, 1, '看哪，弟兄和睦同居是何等地善，何等地美！'),
('00000000-0000-0000-0002-000000000201', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 133, 2, '这好比那贵重的油浇在亚伦的头上，流到胡须，又流到他的衣襟。'),
('00000000-0000-0000-0002-000000000202', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 133, 3, '又好比黑门的甘露降在锡安山；因为在那里有耶和华所命定的福，就是永远的生命。')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000210', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 100, 1, '普天下当向耶和华欢呼！'),
('00000000-0000-0000-0002-000000000211', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 100, 2, '你们当乐意事奉耶和华，当来向他歌唱！'),
('00000000-0000-0000-0002-000000000212', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 100, 3, '你们当晓得耶和华是神！我们是他造的，也是属他的；我们是他的民，也是他草场的羊。'),
('00000000-0000-0000-0002-000000000213', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 100, 4, '当称谢进入他的门；当赞美进入他的院。当感谢他，称颂他的名！'),
('00000000-0000-0000-0002-000000000214', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 100, 5, '因为耶和华本为善。他的慈爱存到永远；他的信实直到万代。')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000220', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 15, 1, '耶和华啊，谁能寄居你的帐幕？谁能住在你的圣山？'),
('00000000-0000-0000-0002-000000000221', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 15, 2, '就是行为正直、做事公义、心里说实话的人。'),
('00000000-0000-0000-0002-000000000222', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 15, 3, '他不以舌头谗谤人，不恶待朋友，也不随伙毁谤邻里；'),
('00000000-0000-0000-0002-000000000223', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 15, 4, '他眼中藐视匪类，却尊重那敬畏耶和华的人。他发了誓，虽然自己吃亏也不更改。'),
('00000000-0000-0000-0002-000000000224', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 15, 5, '他不放债取利，不受贿赂以害无辜。行这些事的人必永不动摇。')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000230', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 128, 1, '凡敬畏耶和华、遵行他道的人便为有福！'),
('00000000-0000-0000-0002-000000000231', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 128, 2, '你要吃劳碌得来的，你要享福，事情顺利。'),
('00000000-0000-0000-0002-000000000232', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 128, 3, '你妻子在你的内室，好像多结果子的葡萄树；你儿女围绕你的桌子，好像橄榄栽子。'),
('00000000-0000-0000-0002-000000000233', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 128, 4, '看哪，敬畏耶和华的人必要这样蒙福！'),
('00000000-0000-0000-0002-000000000234', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 128, 5, '愿耶和华从锡安赐福给你！愿你一生一世看见耶路撒冷的好处！')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000240', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 10, '为义受逼迫的人有福了！因为天国是他们的。'),
('00000000-0000-0000-0002-000000000241', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 11, '人若因我辱骂你们，逼迫你们，捏造各样坏话毁谤你们，你们就有福了！'),
('00000000-0000-0000-0002-000000000242', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 12, '应当欢喜快乐，因为你们在天上的赏赐是大的。在你们以前的先知，人也是这样逼迫他们。')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000250', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 1, '论到从起初原有的生命之道，就是我们所听见、所看见、亲眼看过、亲手摸过的。'),
('00000000-0000-0000-0002-000000000251', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 2, '（这生命已经显现出来，我们也看见过，现在又作见证，将原与父同在、且显现与我们那永远的生命传给你们。）'),
('00000000-0000-0000-0002-000000000252', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 3, '我们将所看见、所听见的传给你们，使你们与我们相交。我们乃是与父并他儿子耶稣基督相交的。'),
('00000000-0000-0000-0002-000000000253', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 4, '我们将这些话写给你们，使你们的喜乐充足。'),
('00000000-0000-0000-0002-000000000254', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 5, '神就是光，在他毫无黑暗。这是我们从主所听见、又报给你们的信息。'),
('00000000-0000-0000-0002-000000000255', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 6, '我们若说是与神相交，却仍在黑暗里行，就是说谎话，不行真理了。'),
('00000000-0000-0000-0002-000000000256', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 7, '我们若在光明中行，如同神在光明中，就彼此相交，他儿子耶稣的血也洗净我们一切的罪。'),
('00000000-0000-0000-0002-000000000257', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 8, '我们若说自己无罪，便是自欺，真理不在我们心里了。'),
('00000000-0000-0000-0002-000000000258', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000062', 1, 9, '我们若认自己的罪，神是信实的，是公义的，必要赦免我们的罪，洗净我们一切的不义。')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000260', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 1, '作神和主耶稣基督仆人的雅各请散住十二个支派之人的安。'),
('00000000-0000-0000-0002-000000000261', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 2, '我的弟兄们，你们落在百般试炼中，都要以为大喜乐；'),
('00000000-0000-0000-0002-000000000262', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 3, '因为知道你们的信心经过试验，就生忍耐。'),
('00000000-0000-0000-0002-000000000263', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 4, '但忍耐也当成功，使你们成全、完备，毫无缺欠。'),
('00000000-0000-0000-0002-000000000264', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 5, '你们中间若有缺少智慧的，应当求那厚赐与众人、也不斥责人的神，主就必赐给他。'),
('00000000-0000-0000-0002-000000000265', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 6, '只要凭着信心求，一点不疑惑；因为那疑惑的人，就像海中的波浪，被风吹动翻腾。'),
('00000000-0000-0000-0002-000000000266', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 7, '这样的人不要想从主那里得什么。'),
('00000000-0000-0000-0002-000000000267', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 8, '心怀二意的人，在他一切所行的路上都不稳定。'),
('00000000-0000-0000-0002-000000000268', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 9, '卑微的弟兄升高，就该喜乐；'),
('00000000-0000-0000-0002-000000000269', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 10, '富足的降卑也该如此，因为他必要过去，如同草上的花一样。'),
('00000000-0000-0000-0002-000000000270', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 11, '太阳出来，热风刮起，草就枯干，花也凋谢，美容就消没了；那富足的人在他所行的事上也要这样衰残。'),
('00000000-0000-0000-0002-000000000271', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 12, '忍受试探的人是有福的，因为他经过试验以后，必得生命的冠冕；这是主应许给那些爱他之人的。'),
('00000000-0000-0000-0002-000000000272', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 13, '人被试探，不可说：我是被神试探；因为神不能被恶试探，他也不试探人。'),
('00000000-0000-0000-0002-000000000273', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 14, '但各人被试探，乃是被自己的私欲牵引诱惑的。'),
('00000000-0000-0000-0002-000000000274', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 15, '私欲既怀了胎，就生出罪来；罪既长成，就生出死来。'),
('00000000-0000-0000-0002-000000000275', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 16, '我亲爱的弟兄们，不要看错了。'),
('00000000-0000-0000-0002-000000000276', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 17, '各样美善的恩赐和各样全备的赏赐都是从上头来的，从众光之父那里降下来的；在他并没有改变，也没有转动的影儿。'),
('00000000-0000-0000-0002-000000000277', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 18, '他按自己的旨意，用真道生了我们，叫我们在他所造的万物中好像初熟的果子。'),
('00000000-0000-0000-0002-000000000278', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 19, '我亲爱的弟兄们，这是你们所知道的。但你们各人要快快地听，慢慢地说，慢慢地动怒，'),
('00000000-0000-0000-0002-000000000279', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000059', 1, 20, '因为人的怒气并不成就神的义。')
